/**
 * ExitIntentPopup — Shows once per session when user's mouse moves toward
 * the top of the viewport on public pages (landing, pricing, features).
 * Dismissed via X or clicking the overlay. Stored in sessionStorage.
 */
import { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { tokens } from '../styles/tokens';
import { track } from '../utils/analytics';
import { tierPrice } from '../config/pricing';

const T = {
  bg: tokens.color.bg,
  surface: tokens.color.surface,
  surface2: tokens.color.surfaceHover,
  border: tokens.color.border,
  text: tokens.color.text,
  textSec: tokens.color.textSecondary,
  green: tokens.color.green,
  blue: tokens.color.blue,
  purple: tokens.color.purple,
  amber: tokens.color.amber,
  mono: tokens.font.mono,
  sans: tokens.font.sans,
};

const STORAGE_KEY = 'exit_intent_shown';
const DELAY_MS = 10000; // 10 seconds before arming

// Simulated spots remaining (decrements per session for urgency)
function getSpotsRemaining() {
  const base = 37; // Feels authentic and urgent
  try {
    const stored = sessionStorage.getItem('exit_intent_spots');
    if (stored) return parseInt(stored, 10);
    const spots = base - Math.floor(Math.random() * 5);
    sessionStorage.setItem('exit_intent_spots', String(spots));
    return spots;
  } catch {
    return base;
  }
}

export default function ExitIntentPopup() {
  const [show, setShow] = useState(false);
  const spots = getSpotsRemaining();

  const dismiss = useCallback(() => {
    setShow(false);
    track('exit_intent_dismissed');
  }, []);

  useEffect(() => {
    // Already shown this session
    if (sessionStorage.getItem(STORAGE_KEY)) return;

    let armed = false;

    const handler = (e) => {
      if (!armed) return;
      // Trigger when mouse leaves the top of viewport
      if (e.clientY < 10 && !sessionStorage.getItem(STORAGE_KEY)) {
        setShow(true);
        sessionStorage.setItem(STORAGE_KEY, '1');
        track('exit_intent_shown');
        document.removeEventListener('mouseleave', handler);
      }
    };

    // Only arm after delay so casual mouse movements don't trigger
    const timer = setTimeout(() => {
      armed = true;
      document.addEventListener('mouseleave', handler);
    }, DELAY_MS);

    return () => {
      clearTimeout(timer);
      document.removeEventListener('mouseleave', handler);
    };
  }, []);

  if (!show) return null;

  return (
    <>
      {/* Dark overlay */}
      <div
        onClick={dismiss}
        style={{
          position: 'fixed', inset: 0, zIndex: 9998,
          background: 'rgba(0,0,0,0.7)',
          backdropFilter: 'blur(4px)',
          WebkitBackdropFilter: 'blur(4px)',
          animation: 'exitIntentFadeIn 0.3s ease',
        }}
      />

      {/* Modal */}
      <div style={{
        position: 'fixed', top: '50%', left: '50%',
        transform: 'translate(-50%, -50%)',
        zIndex: 9999,
        width: '90vw', maxWidth: 480,
        background: tokens.glass.bg,
        backdropFilter: tokens.glass.blur,
        WebkitBackdropFilter: tokens.glass.blur,
        border: `1px solid ${T.green}33`,
        borderRadius: 18,
        padding: 0,
        overflow: 'hidden',
        boxShadow: `0 24px 80px rgba(0,0,0,0.6), 0 0 40px ${T.green}15`,
        animation: 'exitIntentSlideUp 0.4s cubic-bezier(0.16,1,0.3,1)',
      }}>
        {/* Close button */}
        <button
          onClick={dismiss}
          style={{
            position: 'absolute', top: 14, right: 14, zIndex: 1,
            background: 'none', border: 'none', cursor: 'pointer',
            color: T.textSec, fontSize: 20, lineHeight: 1, padding: 4,
            opacity: 0.6,
          }}
          aria-label="Close"
        >
          &#10005;
        </button>

        {/* Accent bar */}
        <div style={{
          height: 3,
          background: `linear-gradient(90deg, ${T.green}, ${T.blue}, ${T.purple})`,
        }} />

        <div style={{ padding: '32px 28px 28px' }}>
          {/* Heading */}
          <h2 style={{
            fontSize: 26, fontWeight: 800, color: T.text,
            fontFamily: T.sans, margin: '0 0 8px', lineHeight: 1.2,
          }}>
            Wait! Don't miss out.
          </h2>

          <p style={{
            fontSize: 15, color: T.textSec, lineHeight: 1.6,
            margin: '0 0 20px', fontFamily: T.sans,
          }}>
            Founding members get <strong style={{ color: T.purple }}>Pro ({tierPrice('pro')})</strong> FREE for life. Limited spots remaining.
          </p>

          {/* Spots remaining badge */}
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 8,
            padding: '8px 16px', borderRadius: 10,
            background: `${T.green}0C`, border: `1px solid ${T.green}25`,
            marginBottom: 24,
          }}>
            <span style={{
              display: 'inline-block', width: 8, height: 8, borderRadius: '50%',
              background: T.green,
              boxShadow: `0 0 8px ${T.green}88`,
              animation: 'exitIntentPulse 2s ease infinite',
            }} />
            <span style={{
              fontSize: 14, fontWeight: 700, fontFamily: T.mono, color: T.green,
            }}>
              {spots}
            </span>
            <span style={{ fontSize: 13, color: T.textSec }}>spots remaining</span>
          </div>

          {/* CTA button */}
          <div>
            <Link
              to="/register"
              onClick={() => track('exit_intent_cta_clicked', { cta: 'claim_spot' })}
              style={{
                display: 'block', textAlign: 'center',
                padding: '14px 24px', borderRadius: 12,
                fontSize: 15, fontWeight: 700, fontFamily: T.mono,
                color: '#fff', textDecoration: 'none',
                background: `linear-gradient(135deg, ${T.green}, ${T.blue})`,
                boxShadow: `0 4px 20px ${T.green}33`,
                transition: 'opacity 0.15s, transform 0.15s',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.9'; e.currentTarget.style.transform = 'translateY(-1px)'; }}
              onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; e.currentTarget.style.transform = 'translateY(0)'; }}
            >
              Claim Your Spot &rarr;
            </Link>
          </div>

          {/* Promo code line */}
          <div style={{
            textAlign: 'center', marginTop: 16,
            fontSize: 13, color: T.textSec, fontFamily: T.sans,
          }}>
            Or use code{' '}
            <span style={{
              fontFamily: T.mono, fontWeight: 700, color: T.amber,
              padding: '2px 8px', borderRadius: 4,
              background: `${T.amber}0C`, border: `1px solid ${T.amber}22`,
            }}>
              LAUNCH50
            </span>
            {' '}for 50% off your first month.
          </div>

          {/* Trust line */}
          <div style={{
            textAlign: 'center', marginTop: 14,
            fontSize: 11, color: T.textSec, opacity: 0.6, fontFamily: T.mono,
          }}>
            Cancel anytime &middot; No credit card required to start
          </div>
        </div>
      </div>

      {/* Inline keyframes */}
      <style>{`
        @keyframes exitIntentFadeIn {
          from { opacity: 0; } to { opacity: 1; }
        }
        @keyframes exitIntentSlideUp {
          from { opacity: 0; transform: translate(-50%, -45%); }
          to   { opacity: 1; transform: translate(-50%, -50%); }
        }
        @keyframes exitIntentPulse {
          0%, 100% { opacity: 1; } 50% { opacity: 0.5; }
        }
      `}</style>
    </>
  );
}
